<?php
declare(strict_types=1);namespace App\Services\ControlEscaneres\Import;final class InitialScannerCsvValidator{private const REQUIRED=['codigo','marca','modelo','estado','activo'];private const ALLOWED=['disponible','entregado','mantenimiento','pendiente_reparacion','baja_definitiva','extraviado'];public function validate(string$file):array{if(!is_readable($file))throw new \InvalidArgumentException('Archivo no legible.');$h=fopen($file,'rb');$headers=array_map(fn($x)=>mb_strtolower(trim((string)$x)),fgetcsv($h)?:[]);if(array_intersect(['pin','puk'],$headers))throw new \InvalidArgumentException('PIN y PUK están prohibidos.');$missing=array_diff(self::REQUIRED,$headers);if($missing)throw new \InvalidArgumentException('Faltan columnas requeridas.');$valid=0;$errors=[];$seen=['codigo'=>[],'serie'=>[],'imei'=>[]];$line=1;while(($values=fgetcsv($h))!==false){$line++;$row=array_combine($headers,array_pad($values,count($headers),''));$row=array_map(fn($x)=>trim((string)$x),$row);$issues=[];if(!preg_match('/^SC-[0-9]{4,}$/',$row['codigo']??''))$issues[]='codigo inválido';if(($row['marca']??'')===''||($row['modelo']??'')==='')$issues[]='marca/modelo requeridos';if(!in_array($row['estado']??'',self::ALLOWED,true))$issues[]='estado inválido';if(!in_array($row['activo']??'',['0','1'],true))$issues[]='activo debe ser 0 o 1';if(($row['imei']??'')!==''&&!preg_match('/^[0-9]{14,16}$/',$row['imei']))$issues[]='IMEI inválido';foreach(['codigo','serie','imei']as$key){$value=$row[$key]??'';if($value!==''&&isset($seen[$key][$value]))$issues[]='duplicado en '.$key;elseif($value!=='')$seen[$key][$value]=true;}if($issues)$errors[]=['line'=>$line,'errors'=>$issues];else$valid++;}fclose($h);return['valid'=>$valid,'invalid'=>count($errors),'errors'=>$errors,'total'=>$valid+count($errors)];}}
